import React from "react";
import InfoPageLayout from "./InfoPageLayout";

const pageData = {
  title: "About Us",
  subtitle: "We're on a mission to make enterprise cybersecurity accessible to every organization. Learn about our journey and team.",
  sections: [
    {
      title: "Our Mission",
      description: "To democratize enterprise-grade cybersecurity, making advanced threat detection and protection available to organizations of all sizes.",
      content: "<p>Founded in 2024 by a team of security veterans from leading technology companies, CyberVault was built on the belief that every organization deserves access to the same level of security that Fortune 500 companies rely on.</p><p>We've combined cutting-edge AI research with decades of cybersecurity expertise to create a platform that's both powerful and easy to use. Our goal is simple: to make the internet a safer place, one organization at a time.</p>"
    },
    {
      title: "Our Values",
      description: "The principles that guide everything we do.",
      bgColor: "#f8fafc",
      gridClass: "info-grid-2",
      grid: [
        {
          title: "Security First",
          description: "Every decision we make considers security implications. We won't ship features that compromise safety."
        },
        {
          title: "Transparency",
          description: "We believe in open communication about our practices, incident response, and product roadmap."
        },
        {
          title: "Innovation",
          description: "We continuously push the boundaries of what's possible in cybersecurity with AI and automation."
        },
        {
          title: "Customer Success",
          description: "Your security is our success. We're committed to helping every customer achieve their security goals."
        }
      ]
    },
    {
      title: "Company Timeline",
      content: `
        <div class="timeline">
          <div class="timeline-item">
            <div class="timeline-date">2024</div>
            <div class="timeline-content">
              <h4>Founded</h4>
              <p>CyberVault founded in San Francisco with seed funding.</p>
            </div>
          </div>
          <div class="timeline-item">
            <div class="timeline-date">2024</div>
            <div class="timeline-content">
              <h4>Platform Launch</h4>
              <p>Core platform launches with AI threat detection.</p>
            </div>
          </div>
          <div class="timeline-item">
            <div class="timeline-date">2025</div>
            <div class="timeline-content">
              <h4>Series A</h4>
              <p>$50M Series A led by top-tier VCs.</p>
            </div>
          </div>
          <div class="timeline-item">
            <div class="timeline-date">2025</div>
            <div class="timeline-content">
              <h4>500+ Customers</h4>
              <p>Reached 500 enterprise customers milestone.</p>
            </div>
          </div>
          <div class="timeline-item">
            <div class="timeline-date">2026</div>
            <div class="timeline-content">
              <h4>Global Expansion</h4>
              <p>Expanded to Europe and Asia Pacific regions.</p>
            </div>
          </div>
        </div>
      `
    },
    {
      title: "Leadership Team",
      description: "Experienced security experts dedicated to protecting your infrastructure.",
      gridClass: "info-grid-3",
      grid: [
        { title: "Sarah Chen", description: "CEO & Co-founder, Former CISO at Fortune 100 company" },
        { title: "Michael Rodriguez", description: "CTO & Co-founder, 20+ years in cybersecurity" },
        { title: "Dr. Emily Watson", description: "Chief AI Officer, PhD in Machine Learning" }
      ]
    },
    {
      stats: [
        { value: "500+", label: "Enterprise Clients" },
        { value: "$50M+", label: "Funding Raised" },
        { value: "10M+", label: "Threats Blocked" },
        { value: "99.9%", label: "Customer Satisfaction" }
      ]
    }
  ],
  color: "#f59e0b"
};

function About() {
  return <InfoPageLayout {...pageData} />;
}

export default About;
